-- ============================================================
-- OLAP AMR Tagihan Listrik Jawa Barat 2026
-- Aggregated from 5 months of AMR data (THBLREK 202602-202607)
-- Generated: 2026-07-07
-- ============================================================

CREATE TABLE IF NOT EXISTS `olap_amr_tagihan` (
  `id` INT AUTO_INCREMENT PRIMARY KEY,
  `thblrek` CHAR(6) NOT NULL COMMENT 'Periode rekening YYYYMM',
  `unitap` VARCHAR(10) NOT NULL COMMENT 'Kode UP3',
  `unitap_nama` VARCHAR(50) NOT NULL COMMENT 'Nama UP3',
  `unitup` VARCHAR(10) NOT NULL COMMENT 'Kode ULP',
  `tarif` VARCHAR(10) NOT NULL COMMENT 'Golongan tarif',
  `tarif_grup` VARCHAR(20) NOT NULL COMMENT 'Kelompok tarif',
  `jml_pelanggan` INT NOT NULL DEFAULT 0,
  `kwh_total` DECIMAL(18,3) NOT NULL DEFAULT 0,
  `kwh_lwbp` DECIMAL(18,3) NOT NULL DEFAULT 0,
  `kwh_wbp` DECIMAL(18,3) NOT NULL DEFAULT 0,
  `rp_ptl` BIGINT NOT NULL DEFAULT 0 COMMENT 'Tagihan tarif dasar (Rp)',
  `rp_ppj` BIGINT NOT NULL DEFAULT 0 COMMENT 'BPJU / PPJ (Rp)',
  `rp_total` BIGINT NOT NULL DEFAULT 0 COMMENT 'Total tagihan (Rp)',
  `created_at` TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  UNIQUE KEY `uk_olap_amr` (`thblrek`, `unitap`, `unitup`, `tarif`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;





























-- ============================================================
-- Registrasi modul di domain_modules
-- Domain energi-jabar = id 1 (sesuai DB existing)
-- ============================================================

   '/modules/energi-jabar/z6f56zbbq2pi/', 'internal', 'aktif', NOW())
ON DUPLICATE KEY UPDATE
  `url_token`     = VALUES(`url_token`),
  `nama`          = VALUES(`nama`),
  `route_path`    = VALUES(`route_path`),
  `status`        = VALUES(`status`),
  `data_updated_at` = VALUES(`data_updated_at`);

-- ============================================================
-- Fix nama UP3: 53CKG bukan Cikokol, tapi Cikarang
-- ============================================================
UPDATE `olap_amr_tagihan` SET `unitap_nama` = 'UP3 Cikarang' WHERE `unitap` = '53CKG';
